public class App {
    public static void main(String[] args) {
        Thread t = new Thread(() -> System.out.println("Hello from thread: " + Thread.currentThread().getName()));
        t.start();
    }
}

class MyThread extends Thread {
    @Override public void run() {
        System.out.println("Thread via extend: " + Thread.currentThread().getName());
    }
}
class MyRunnable implements Runnable {
    @Override public void run() {
        System.out.println("Thread via Runnable: " + Thread.currentThread().getName());
    }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        Thread t1 = new MyThread();
        Thread t2 = new Thread(new MyRunnable());
        Thread t3 = new Thread(() -> System.out.println("Thread via lambda: " + Thread.currentThread().getName()));
        t1.start(); t2.start(); t3.start();
        t1.join(); t2.join(); t3.join();
    }
}

public class App {
