public class App {
    static void doWork() {
        try { Thread.sleep(500); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    public static void main(String[] args) throws InterruptedException {
        // Sequential
        long seqStart = System.currentTimeMillis();
        doWork(); doWork(); doWork();
        long seqTime = System.currentTimeMillis() - seqStart;
        System.out.println("Sequential: ~" + (seqTime / 100 * 100) + "ms");

        // Parallel
        long parStart = System.currentTimeMillis();
        Thread t1 = new Thread(App::doWork);
        Thread t2 = new Thread(App::doWork);
        Thread t3 = new Thread(App::doWork);
        t1.start(); t2.start(); t3.start();
        t1.join(); t2.join(); t3.join();
        long parTime = System.currentTimeMillis() - parStart;
        System.out.println("Parallel: ~" + (parTime / 100 * 100) + "ms");
    }
}

