public class App {
    public static void main(String[] args) throws InterruptedException {
        Thread daemon = new Thread(() -> {
            while (true) {
                System.out.println("Daemon tick");
                try { Thread.sleep(200); } catch (InterruptedException e) { return; }
            }
        });
        daemon.setDaemon(true);  // MUST be set before start()
        daemon.start();

        Thread.sleep(500);  // main runs for 500ms
        System.out.println("Main done — JVM will exit");
        // JVM exits here; daemon thread is killed
    }
}

import java.util.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        int[] delays = {400, 200, 500, 100, 300};
        Thread[] threads = new Thread[delays.length];
        long start = System.currentTimeMillis();

        for (int i = 0; i < delays.length; i++) {
            final int n = i + 1;
            final int delay = delays[i];
            threads[i] = new Thread(() -> {
                try { Thread.sleep(delay); } 
                catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
                System.out.printf("File-%d done (%dms)%n", n, delay);
            }, "FileProcessor-" + n);
        }

        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();

        System.out.printf("All files processed in %dms%n",
            System.currentTimeMillis() - start);
    }
}

