import java.util.*;
import java.util.concurrent.*;
public class App {
    public static void main(String[] args) throws InterruptedException {
        int numWorkers = 3;
        int numTasks = 8;
        LinkedBlockingQueue<Integer> taskQueue = new LinkedBlockingQueue<>();
        for (int i = 1; i <= numTasks; i++) taskQueue.add(i);

        Thread[] workers = new Thread[numWorkers];
        for (int w = 0; w < numWorkers; w++) {
            final int workerNum = w + 1;
            workers[w] = new Thread(() -> {
                Integer task;
                while ((task = taskQueue.poll()) != null) {
                    final int t = task;
                    System.out.printf("Worker-%d processing task-%d%n", workerNum, t);
                    try { Thread.sleep(100); } 
                    catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
                    System.out.printf("Worker-%d done with task-%d%n", workerNum, t);
                }
            }, "Worker-" + workerNum);
        }

        for (Thread w : workers) w.start();
        for (Thread w : workers) w.join();
        System.out.println("All " + numTasks + " tasks completed");
    }
}

class Station implements Runnable {
    String name; int ms;
    Station(String n, int m) { name=n; ms=m; }
    public void run() {
        long start = System.currentTimeMillis();
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
        System.out.printf("%s ready (%dms)%n", name, System.currentTimeMillis()-start);
    }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        long kitchenOpen = System.currentTimeMillis();
        Thread[] stations = {
            new Thread(new Station("Drinks",  200)),
            new Thread(new Station("Starter", 400)),
            new Thread(new Station("Main",    800)),
            new Thread(new Station("Dessert", 300))
        };
        for (Thread s : stations) s.start();
        for (Thread s : stations) s.join();
        System.out.printf("All served in ~%dms%n",
            (System.currentTimeMillis()-kitchenOpen)/100*100);
    }
}

public class App {
    static volatile boolean found = false;
    static volatile String finder = "";

    public static void main(String[] args) throws InterruptedException {
        final int target = 573;
        final int rangeSize = 250;
        Thread[] threads = new Thread[4];

        for (int t = 0; t < 4; t++) {
            final int start = t * rangeSize + 1;
            final int end   = (t == 3) ? 1000 : start + rangeSize - 1;
            final String name = "Thread-" + (t+1);

            threads[t] = new Thread(() -> {
                for (int i = start; i <= end && !found; i++) {
                    if (i == target) {
                        found = true;
                        finder = name + " found " + target + " in range [" + start + ", " + end + "]";
                        return;
                    }
                }
            }, name);
        }

        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        System.out.println(finder.isEmpty() ? "Not found" : finder);
        System.out.println("Search complete");
    }
}
